   301→        const noteToDelete = get().notes[id];
   302→        if (!noteToDelete) {
   303→          log.warn('Note not found', { id });
   304→          return;
   305→        }
   306→
   307→        // Store the previous activeNoteId for undo
   308→        const wasActive = get().activeNoteId === id;
   309→
