    33→  showSuggestions?: boolean;
    34→}
    35→
    36→export function TagPicker({
    37→  selectedTags,
    38→  onAddTag,
    39→  onRemoveTag,
    40→  maxTags = 20,
    41→  content = '',
    42→  showSuggestions = true
    43→}: TagPickerProps) {
    44→  const [isOpen, setIsOpen] = useState(false);
    45→  const [searchQuery, setSearchQuery] = useState('');
