    55→
    56→  // Cache the notes array to prevent infinite re-renders
    57→  const allNotes = useMemo(() => Object.values(notesSnapshot), [notesSnapshot]);
    58→
    59→  // Generate smart tag suggestions
    60→  const suggestions = useMemo(() => {
    61→    if (!showSuggestions || !content) return [];
    62→    return generateTagSuggestions(content, selectedTags, allNotes, 5);
    63→  }, [showSuggestions, content, selectedTags, allNotes]);
    64→
    65→  // Build tag tree from all tags
    66→  const tagTree = useMemo(() => buildTagTree(allTags), [allTags]);
    67→
    68→  // Filter tags based on search query and exclude already selected
    69→  const filteredTags = allTags.filter(
    70→    (tag) =>
    71→      !selectedTags.includes(tag) &&
    72→      tag.toLowerCase().includes(searchQuery.toLowerCase())
    73→  );
    74→
    75→  // Show recent tags if no search query
    76→  const suggestedTags = searchQuery
    77→    ? filteredTags.slice(0, 10)
