    79→
    80→  // Handle click outside to close
    81→  useEffect(() => {
    82→    function handleClickOutside(event: MouseEvent) {
    83→      if (
    84→        dropdownRef.current &&
    85→        !dropdownRef.current.contains(event.target as Node) &&
    86→        inputRef.current &&
    87→        !inputRef.current.contains(event.target as Node)
    88→      ) {
    89→        setIsOpen(false);
    90→        setSearchQuery('');
    91→      }
    92→    }
    93→
    94→    if (isOpen) {
    95→      document.addEventListener('mousedown', handleClickOutside);
    96→      return () => document.removeEventListener('mousedown', handleClickOutside);
    97→    }
    98→  }, [isOpen]);
    99→
   100→  // Focus input when opened
   101→  useEffect(() => {
   102→    if (isOpen && inputRef.current) {
   103→      inputRef.current.focus();
   104→    }
   105→  }, [isOpen]);
   106→
   107→  const handleAddTag = (tag: string) => {
   108→    const normalizedTag = normalizeTag(tag);
   109→    if (!normalizedTag) return;
   110→    if (selectedTags.includes(normalizedTag)) return;
   111→    if (selectedTags.length >= maxTags) return;
   112→
   113→    onAddTag(normalizedTag);
   114→    setSearchQuery('');
