   176→          )}
   177→        </button>
   178→
   179→        {/* Render children if expanded */}
   180→        {hasChildren && isExpanded && (
   181→          <div>
   182→            {node.children.map(child => renderTagNode(child))}
   183→          </div>
   184→        )}
   185→      </div>
   186→    );
   187→  };
   188→
   189→  const handleKeyDown = (e: React.KeyboardEvent) => {
   190→    if (e.key === 'Enter') {
   191→      e.preventDefault();
   192→      if (searchQuery.trim()) {
