   201→  };
   202→
   203→  const canAddMore = selectedTags.length < maxTags;
   204→
   205→  return (
   206→    <div className="relative">
   207→      {/* Selected Tags Display */}
   208→      <div className="flex flex-wrap gap-2 items-center">
   209→        {selectedTags.map((tag) => {
   210→          const color = tagColors[tag];
   211→          return (
