   225→                  color
   226→                    ? `hover:bg-${color}/20 dark:hover:bg-${color}/30`
   227→                    : 'hover:bg-accent-purple/20 dark:hover:bg-accent-cyan/20'
   228→                }`}
   229→                aria-label={`Remove tag ${tag}`}
   230→              >
   231→                <X className="w-3 h-3" />
   232→              </button>
   233→            </span>
   234→          );
   235→        })}
   236→
   237→        {/* Add Tag Button */}
   238→        {canAddMore && (
   239→          <button
   240→            onClick={() => setIsOpen(!isOpen)}
   241→            className="inline-flex items-center gap-1 px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-colors"
   242→            aria-label="Add tag"
   243→          >
   244→            <Plus className="w-3 h-3" />
   245→            Add tag
