   257→        </div>
   258→      )}
   259→
   260→      {/* Tag Picker Dropdown */}
   261→      {isOpen && (
   262→        <div
   263→          ref={dropdownRef}
   264→          className="absolute z-50 mt-2 w-64 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg shadow-lg"
   265→        >
   266→          {/* Search Input */}
   267→          <div className="p-2 border-b border-border-light dark:border-border-dark">
   268→            <input
   269→              ref={inputRef}
   270→              type="text"
   271→              value={searchQuery}
   272→              onChange={(e) => setSearchQuery(e.target.value)}
   273→              onKeyDown={handleKeyDown}
   274→              placeholder="Search or create tag..."
   275→              className="w-full px-3 py-2 text-sm bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded focus:outline-none focus:ring-2 focus:ring-accent-purple dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
   276→            />
   277→          </div>
   278→
   279→          {/* Tag Suggestions */}
   280→          <div className="max-h-64 overflow-y-auto">
   281→            {searchQuery ? (
   282→              /* Flat filtered list when searching */
   283→              <>
   284→                {!filteredTags.includes(searchQuery) && (
   285→                  <button
   286→                    onClick={() => handleAddTag(searchQuery)}
   287→                    className="w-full px-3 py-2 text-left text-sm hover:bg-surface-light dark:hover:bg-surface-dark transition-colors text-text-light-primary dark:text-text-dark-primary"
   288→                  >
   289→                    <div className="flex items-center gap-2">
   290→                      <Plus className="w-4 h-4 text-accent-purple dark:text-accent-cyan" />
   291→                      <span>
   292→                        Create "<span className="font-medium">{searchQuery}</span>"
   293→                      </span>
   294→                    </div>
   295→                  </button>
   296→                )}
   297→
   298→                {filteredTags.length > 0 ? (
   299→                  filteredTags.slice(0, 10).map((tag) => (
   300→                    <button
   301→                      key={tag}
   302→                      onClick={() => handleAddTag(tag)}
   303→                      className="w-full px-3 py-2 text-left text-sm hover:bg-surface-light dark:hover:bg-surface-dark transition-colors text-text-light-primary dark:text-text-dark-primary"
   304→                    >
   305→                      <div className="flex items-center gap-2">
   306→                        <TagIcon className="w-4 h-4 text-accent-purple dark:text-accent-cyan" />
   307→                        {tag}
   308→                      </div>
   309→                    </button>
