   252→      return;
   253→    }
   254→
   255→    const notesToDelete = Object.values(notesObj).filter(note => note.folderId === selectedFolderId);
   256→    const noteCount = notesToDelete.length;
   257→
   258→    // Delete all notes in this folder (without undo since folder undo will handle it)
   259→    // We need to temporarily bypass the undo system for individual notes
   260→    notesToDelete.forEach(note => {
   261→      // Call the store action directly without triggering undo
   262→      useNotesStore.setState((state) => {
   263→        const { [note.id]: deleted, ...remainingNotes } = state.notes;
   264→        return {
   265→          notes: remainingNotes,
   266→          activeNoteId: state.activeNoteId === note.id ? null : state.activeNoteId,
   267→        };
   268→      });
   269→    });
