  1065→            ref={sidebarRef}
  1066→            initial={{ width: 0, opacity: 0 }}
  1067→            animate={{ width: sidebarWidth, opacity: 1 }}
  1068→            exit={{ width: 0, opacity: 0 }}
  1069→            transition={{ duration: 0.2 }}
  1070→            className="flex-shrink-0 border-r border-border-light dark:border-border-dark bg-transparent flex flex-col relative"
  1071→            style={{ width: sidebarWidth }}
  1072→          >
  1073→            <FolderSidebar
  1074→              activeTags={activeTags}
  1075→              onAddTag={handleAddTag}
  1076→              onRemoveTag={handleRemoveTag}
  1077→              onClearAllTags={handleClearAllTags}
  1078→              onOpenTagManager={() => setShowTagManager(true)}
  1079→            />
  1080→            <NotesList activeTags={activeTags} />
  1081→
  1082→            {/* Collapse button - inside sidebar at top right */}
  1083→            <button
  1084→              onClick={() => setIsSidebarCollapsed(true)}
  1085→              className="absolute top-4 right-2 z-20 p-1.5 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button hover:bg-surface-light-elevated dark:hover:bg-neutral-800 transition-all duration-200"
  1086→              title="Collapse Sidebar"
  1087→            >
  1088→              <svg className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
  1089→                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 19l-7-7 7-7m8 14l-7-7 7-7" />
  1090→              </svg>
  1091→            </button>
  1092→
  1093→            {/* Resize handle */}
  1094→            <div
  1095→              onMouseDown={handleMouseDown}
  1096→              className={`absolute right-0 top-0 bottom-0 w-1 cursor-ew-resize hover:bg-accent-blue/50 transition-colors ${isResizing ? 'bg-accent-blue' : ''}`}
  1097→              title="Drag to resize"
  1098→            />
  1099→          </motion.div>
  1100→        )}
  1101→      </AnimatePresence>
  1102→
  1103→        {/* Sidebar expand button - shown when collapsed */}
  1104→        {isSidebarCollapsed && (
  1105→          <button
  1106→            onClick={() => setIsSidebarCollapsed(false)}
  1107→            className="flex-shrink-0 p-2 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-r-lg hover:bg-surface-light-elevated dark:hover:bg-neutral-800 transition-all duration-200 self-start mt-4 ml-2"
  1108→            title="Expand Sidebar"
  1109→          >
  1110→            <svg className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
  1111→              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
  1112→            </svg>
  1113→          </button>
  1114→        )}
  1115→
  1116→        {/* Spacer between sidebar and editor */}
  1117→        {!isSidebarCollapsed && <div className="w-4 flex-shrink-0" />}
  1118→
  1119→      {/* Center - Editor or Calendar */}
  1120→      <div className="flex-1 overflow-hidden flex flex-col">
  1121→        {/* View Toggle (only shown when no note selected and daily notes enabled) */}
  1122→        {!activeNoteId && dailyNotesEnabled && (
  1123→          <div className="flex gap-2 mb-4 px-4">
  1124→            <button
  1125→              onClick={() => setShowCalendar(false)}
  1126→              className={`px-4 py-2 rounded-button text-sm font-medium transition-all ${
  1127→                !showCalendar
  1128→                  ? 'bg-accent-magenta dark:bg-accent-cyan text-white'
  1129→                  : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
  1130→              }`}
  1131→            >
  1132→              Notes
  1133→            </button>
  1134→            <button
