            <kbd className="px-2 py-1 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded font-mono text-xs">Cmd+K</kbd>
            Search notes
          </p>
        </div>
      </div>
    </div>
  );
};

