  /* Hashtag Styles - Inline tagging syntax */
  .hashtag {
    cursor: pointer;
    font-weight: 500;
    @apply bg-primary-cyan/10 dark:bg-primary-cyan/20;
    @apply text-primary-cyan;
    @apply rounded px-1;
